public:
    bool isFascinating(int n) {
        int val = n * 1000000 + (n * 2) * 1000 + (n * 3);
        int mask = 0;
        while (val) {
            int d = val % 10;
            if (d == 0 || (mask >> d) & 1) return false;
            mask |= 1 << d;
            val /= 10;
        }
        return mask == 0b1111111110;
    }
